#nullable enable // autogenerated

using MVZ2.Vanilla.Contraptions;
using MVZ2.Vanilla.Level;

using PVZEngine.Entities;

namespace MVZ2.Vanilla.Entities
{
    public abstract class ContraptionBehaviour : AIEntityBehaviour, IContraptionEvokeBehaviour, ITriggerableContraption
    {
        public ContraptionBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public virtual bool CanEvoke(Entity entity)
        {
            return !entity.IsEvoked() && !entity.IsAIFrozen() && !entity.NoEvoke();
        }
        public virtual void Evoke(Entity entity)
        {
            OnEvoke(entity);
        }
        public virtual bool CanTrigger(Entity entity)
        {
            if (!entity.IsTriggerActive() || entity.IsAIFrozen())
                return false;

            // 劤藤：쇱꿴샙筠콘角뤠璃뭘  
            var triggerCost = entity.GetTriggerCost();
            if (triggerCost > 0 && !entity.Level.IsNoEnergy())
            {
                if (entity.Level.Energy < triggerCost)
                    return false;
            }

            return true;
        }
        public virtual void Trigger(Entity entity)
        {
            // 劤藤：왱뇜뇰랙빻롤  
            var triggerCost = entity.GetTriggerCost();
            if (triggerCost > 0 && !entity.Level.IsNoEnergy())
            {
                entity.Level.AddEnergy(-triggerCost);
            }
            OnTrigger(entity);
        }
        protected virtual void OnTrigger(Entity entity)
        {

        }
        protected virtual void OnEvoke(Entity entity)
        {

        }

    }
}